/*
 * egtm_atom_3_phase_inverter_pwm.c
 *
 * Production driver for EGTM ATOM 3-phase complementary PWM with ADC trigger (TC4xx).
 *
 * Implements:
 *  - initEgtmAtom3phInv(): EGTM ATOM0 CH0..2 center-aligned 20 kHz + 1 us DTM, ATOM0 CH3 50% edge trigger to ADC
 *  - updateEgtmAtom3phInvDuty(): immediate duty update per logical channel
 *  - resultISR(): ADC conversion-complete ISR toggling LED (P03.9)
 *
 * Notes:
 *  - Follows iLLD initialization patterns, EGTM CMU enable-guard, and migration to EGTM for TC4xx.
 *  - Watchdog handling must be performed only in CpuX_Main.c (not in this module).
 */

#include "egtm_atom_3_phase_inverter_pwm.h"

#include "Ifx_Types.h"
#include "IfxEgtm.h"
#include "IfxEgtm_Cmu.h"
#include "IfxEgtm_Pwm.h"
#include "IfxEgtm_Atom_Timer.h"
#include "IfxEgtm_Trigger.h"
#include "IfxEgtm_PinMap.h"
#include "IfxPort.h"
#include "IfxPort_PinMap.h"

/* =====================================================================
 * Macros (numeric configuration from requirements)
 * ===================================================================== */
#define NUM_OF_CHANNELS                 (3U)
#define PWM_FREQUENCY                   (20000.0f)   /* Hz */
#define PHASE_U_DUTY                    (25.0f)      /* % */
#define PHASE_V_DUTY                    (50.0f)      /* % */
#define PHASE_W_DUTY                    (75.0f)      /* % */
#define PHASE_DUTY_STEP                 (0.01f)      /* % */
#define ISR_PRIORITY_ATOM               (25)         /* ADC result ISR priority on cpu0 */

/* LED on P03.9: compound macro for IfxPort_* APIs */
#define LED                             &MODULE_P03, 9

/* =====================================================================
 * Pin macros (validated list used; unavailable mappings set to NULL_PTR)
 * ===================================================================== */
/* Phase U: ATOM0 CH0 (HS) and CH0N (LS) → user-requested P02.0 / P02.1 (validated) */
#define PHASE_U_HS   (&IfxEgtm_ATOM0_0_TOUT0_P02_0_OUT)
#define PHASE_U_LS   (&IfxEgtm_ATOM0_0N_TOUT1_P02_1_OUT)

/* Phase V: ATOM0 CH1 (HS) and CH1N (LS) → user-requested P02.2 / P02.3 (no validated symbol provided) */
#define PHASE_V_HS   (NULL_PTR) /* Replace with &IfxEgtm_ATOM0_1_TOUT2_P02_2_OUT when validated */
#define PHASE_V_LS   (NULL_PTR) /* Replace with &IfxEgtm_ATOM0_1N_TOUT3_P02_3_OUT when validated */

/* Phase W: ATOM0 CH2 (HS) and CH2N (LS) → user-requested P02.4 / P02.5 (no validated symbol provided) */
#define PHASE_W_HS   (NULL_PTR) /* Replace with &IfxEgtm_ATOM0_2_TOUT4_P02_4_OUT when validated */
#define PHASE_W_LS   (NULL_PTR) /* Replace with &IfxEgtm_ATOM0_2N_TOUT5_P02_5_OUT when validated */

/* ADC Trigger TOUT (ATOM0 CH3) → user-requested P33.0 (no validated symbol provided) */
#define ADC_TRIG_TOUT   (NULL_PTR) /* Replace with &IfxEgtm_ATOM0_3_TOUTx_P33_0_OUT when validated */

/* =====================================================================
 * Module persistent state
 * ===================================================================== */

typedef struct
{
    IfxEgtm_Pwm              pwm;                                 /* Unified EGTM PWM driver handle */
    IfxEgtm_Pwm_Channel      channels[NUM_OF_CHANNELS];           /* Channel runtime data (must persist) */
    float32                  dutyCycles[NUM_OF_CHANNELS];         /* Duty percent per phase */
    float32                  phases[NUM_OF_CHANNELS];             /* Phase offsets in seconds (design = 0) */
    IfxEgtm_Pwm_DeadTime     deadTimes[NUM_OF_CHANNELS];          /* Applied dead-times */
} EgtmAtom3ph_State;

IFX_STATIC EgtmAtom3ph_State g_egtmAtom3ph = {0};

/* =====================================================================
 * Internal helpers, ISRs, and callbacks
 * ===================================================================== */

/* Period-event callback placeholder (must be visible; empty body) */
void IfxEgtm_periodEventFunction(void *data)
{
    (void)data;
}

/* ADC result ISR: minimal, toggle LED only */
IFX_INTERRUPT(resultISR, 0, ISR_PRIORITY_ATOM)
{
    IfxPort_togglePin(LED);
}

/* Private helper to configure ATOM trigger routing (TOUT + ADC trigger fabric) */
static void configureEgtmAtomTrigger(uint8 channel)
{
    /* Route ATOM0 CHx to physical TOUT if a validated pin is provided */
    if (ADC_TRIG_TOUT != NULL_PTR)
    {
        IfxEgtm_PinMap_setAtomTout(ADC_TRIG_TOUT, IfxPort_OutputMode_pushPull, IfxPort_PadDriver_cmosAutomotiveSpeed1);
    }

    /* Connect ATOM0 CHx to ADC trigger fabric (AdcTriggerSignal_0 as specified) */
    /* Edge sense and mux select are board/system specific; API here exposes the signal selection. */
    (void)IfxEgtm_Trigger_trigToAdc(IfxEgtm_Cluster_0,
                                    IfxEgtm_TrigSource_atom0,
                                    (IfxEgtm_TrigChannel)channel,
                                    IfxEgtm_Cfg_AdcTriggerSignal_0);
}

/* =====================================================================
 * Public API implementations
 * ===================================================================== */

/**
 * Initialize EGTM CLS0 ATOM resources for complementary 3-phase PWM (CH0..2) and an ADC trigger (CH3).
 */
void initEgtmAtom3phInv(void)
{
    /* 1) Declare configuration structures (locals) */
    IfxEgtm_Pwm_Config         config;
    IfxEgtm_Pwm_ChannelConfig  channelConfig[NUM_OF_CHANNELS];
    IfxEgtm_Pwm_OutputConfig   output[NUM_OF_CHANNELS];
    IfxEgtm_Pwm_DtmConfig      dtmConfig[NUM_OF_CHANNELS];

    IfxEgtm_Atom_Timer         triggerTimer; /* ATOM0 CH3 trigger timer/edge generator */

    /* 2) Load default config */
    IfxEgtm_Pwm_initConfig(&config, &MODULE_EGTM);

    /* 3) Populate output[] for complementary pairs (HS active-high, LS active-low) */
    /* Phase U */
    output[0].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_U_HS;
    output[0].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_U_LS;
    output[0].polarity              = Ifx_ActiveState_high;
    output[0].complementaryPolarity = Ifx_ActiveState_low;
    output[0].outputMode            = IfxPort_OutputMode_pushPull;
    output[0].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* Phase V */
    output[1].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_V_HS; /* May be NULL_PTR until validated */
    output[1].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_V_LS; /* May be NULL_PTR until validated */
    output[1].polarity              = Ifx_ActiveState_high;
    output[1].complementaryPolarity = Ifx_ActiveState_low;
    output[1].outputMode            = IfxPort_OutputMode_pushPull;
    output[1].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* Phase W */
    output[2].pin                   = (IfxEgtm_Pwm_ToutMap *)PHASE_W_HS; /* May be NULL_PTR until validated */
    output[2].complementaryPin      = (IfxEgtm_Pwm_ToutMap *)PHASE_W_LS; /* May be NULL_PTR until validated */
    output[2].polarity              = Ifx_ActiveState_high;
    output[2].complementaryPolarity = Ifx_ActiveState_low;
    output[2].outputMode            = IfxPort_OutputMode_pushPull;
    output[2].padDriver             = IfxPort_PadDriver_cmosAutomotiveSpeed1;

    /* 4) DTM configuration: 1.0 us dead-time on rising and falling, DTM clock from CMU CLK0 */
    dtmConfig[0].deadTime.rising = 1.0e-6f;
    dtmConfig[0].deadTime.falling = 1.0e-6f;
    dtmConfig[0].fastShutOff = NULL_PTR;

    dtmConfig[1].deadTime.rising = 1.0e-6f;
    dtmConfig[1].deadTime.falling = 1.0e-6f;
    dtmConfig[1].fastShutOff = NULL_PTR;

    dtmConfig[2].deadTime.rising = 1.0e-6f;
    dtmConfig[2].deadTime.falling = 1.0e-6f;
    dtmConfig[2].fastShutOff = NULL_PTR;

    /* 5) Channel configuration (logical indices 0..2) */
    /* CH0 → Phase U */
    channelConfig[0].timerCh   = IfxEgtm_Pwm_SubModule_Ch_0;
    channelConfig[0].phase     = 0.0f;
    channelConfig[0].duty      = PHASE_U_DUTY;
    channelConfig[0].dtm       = &dtmConfig[0];
    channelConfig[0].output    = &output[0];
    channelConfig[0].mscOut    = NULL_PTR;
    channelConfig[0].interrupt = NULL_PTR; /* No PWM period interrupt */

    /* CH1 → Phase V */
    channelConfig[1].timerCh   = IfxEgtm_Pwm_SubModule_Ch_1;
    channelConfig[1].phase     = 0.0f;
    channelConfig[1].duty      = PHASE_V_DUTY;
    channelConfig[1].dtm       = &dtmConfig[1];
    channelConfig[1].output    = &output[1];
    channelConfig[1].mscOut    = NULL_PTR;
    channelConfig[1].interrupt = NULL_PTR; /* No PWM period interrupt */

    /* CH2 → Phase W */
    channelConfig[2].timerCh   = IfxEgtm_Pwm_SubModule_Ch_2;
    channelConfig[2].phase     = 0.0f;
    channelConfig[2].duty      = PHASE_W_DUTY;
    channelConfig[2].dtm       = &dtmConfig[2];
    channelConfig[2].output    = &output[2];
    channelConfig[2].mscOut    = NULL_PTR;
    channelConfig[2].interrupt = NULL_PTR; /* No PWM period interrupt */

    /* Main PWM configuration */
    config.cluster            = IfxEgtm_Cluster_0;
    config.subModule          = IfxEgtm_Pwm_SubModule_atom;
    config.alignment          = IfxEgtm_Pwm_Alignment_center;
    config.numChannels        = (uint8)NUM_OF_CHANNELS;
    config.channels           = &channelConfig[0];
    config.frequency          = PWM_FREQUENCY;
    config.clockSource.atom   = (uint32)IfxEgtm_Cmu_Clk_0;     /* UNION field for ATOM */
    config.dtmClockSource     = IfxEgtm_Dtm_ClockSource_cmuClock0;
    config.syncUpdateEnabled  = TRUE;                           /* shadow transfer at period end */
    config.syncStart          = TRUE;

    /* 6) EGTM CMU enable-guard: enable module, set GCLK and CLK0 to module frequency, enable only CLK0 */
    if (!IfxEgtm_isEnabled(&MODULE_EGTM))
    {
        IfxEgtm_enable(&MODULE_EGTM);
        float32 freq = IfxEgtm_Cmu_getModuleFrequency(&MODULE_EGTM);
        IfxEgtm_Cmu_setGclkFrequency(&MODULE_EGTM, freq);
        IfxEgtm_Cmu_setClkFrequency(&MODULE_EGTM, IfxEgtm_Cmu_Clk_0, freq);
        IfxEgtm_Cmu_enableClocks(&MODULE_EGTM, (uint32)(IFXEGTM_CMU_CLKEN_FXCLK | IFXEGTM_CMU_CLKEN_CLK0));
    }

    /* 7) Initialize unified EGTM PWM (applies initial duties and dead-times) */
    IfxEgtm_Pwm_init(&g_egtmAtom3ph.pwm, g_egtmAtom3ph.channels, &config);

    /* Persist state (duties, phases, dead-times) */
    g_egtmAtom3ph.dutyCycles[0] = channelConfig[0].duty; g_egtmAtom3ph.phases[0] = channelConfig[0].phase; g_egtmAtom3ph.deadTimes[0] = dtmConfig[0].deadTime;
    g_egtmAtom3ph.dutyCycles[1] = channelConfig[1].duty; g_egtmAtom3ph.phases[1] = channelConfig[1].phase; g_egtmAtom3ph.deadTimes[1] = dtmConfig[1].deadTime;
    g_egtmAtom3ph.dutyCycles[2] = channelConfig[2].duty; g_egtmAtom3ph.phases[2] = channelConfig[2].phase; g_egtmAtom3ph.deadTimes[2] = dtmConfig[2].deadTime;

    /* 8) Configure ATOM0 CH3 as 50% edge-aligned trigger source at 20 kHz */
    {
        /* Frequency → period, then 50% trigger point. The driver object is used directly in this context. */
        (void)IfxEgtm_Atom_Timer_setFrequency(&triggerTimer, PWM_FREQUENCY);
        uint32 period = IfxEgtm_Atom_Timer_getPeriod(&triggerTimer);
        uint32 triggerPoint = (period / 2U);
        IfxEgtm_Atom_Timer_setTrigger(&triggerTimer, triggerPoint);
        IfxEgtm_Atom_Timer_run(&triggerTimer);
    }

    /* 9) Route ATOM0 CH3 to TOUT and connect to ADC trigger fabric */
    configureEgtmAtomTrigger((uint8)IfxEgtm_Pwm_SubModule_Ch_3);

    /* 10) Configure LED GPIO pin (P03.9) as push-pull output */
    IfxPort_setPinModeOutput(LED, IfxPort_OutputMode_pushPull, IfxPort_OutputIdx_general);
}

/**
 * Update the three logical PWM channel duties immediately (percent 0..100).
 */
void updateEgtmAtom3phInvDuty(float32 *requestDuty)
{
    float32 d0 = requestDuty[0];
    float32 d1 = requestDuty[1];
    float32 d2 = requestDuty[2];

    /* Clamp to [0, 100] */
    if (d0 < 0.0f) { d0 = 0.0f; } else if (d0 > 100.0f) { d0 = 100.0f; }
    if (d1 < 0.0f) { d1 = 0.0f; } else if (d1 > 100.0f) { d1 = 100.0f; }
    if (d2 < 0.0f) { d2 = 0.0f; } else if (d2 > 100.0f) { d2 = 100.0f; }

    /* Store into state */
    g_egtmAtom3ph.dutyCycles[0] = d0;
    g_egtmAtom3ph.dutyCycles[1] = d1;
    g_egtmAtom3ph.dutyCycles[2] = d2;

    /* Apply to hardware immediately per logical channel */
    IfxEgtm_Pwm_updateChannelDutyImmediate(&g_egtmAtom3ph.pwm, IfxEgtm_Pwm_SyncChannelIndex_0, d0);
    IfxEgtm_Pwm_updateChannelDutyImmediate(&g_egtmAtom3ph.pwm, IfxEgtm_Pwm_SyncChannelIndex_1, d1);
    IfxEgtm_Pwm_updateChannelDutyImmediate(&g_egtmAtom3ph.pwm, IfxEgtm_Pwm_SyncChannelIndex_2, d2);
}
